// simple date picker for use within Zion form
// derived from FullnameFields.js in zion-ui
// uses first month at 1 (not zero)
import React, { useMemo } from 'react'
import { listOfDays, listOfMonths, listOfYears } from '@fs/zion-locale'
import { FormInputGroup, FormSelect } from '@fs/zion-form'
import { useTranslation } from 'react-i18next'
import { Row } from '@fs/zion-ui'
import getDayMonthYearOrder from './getDayMonthYearOrder'

const currentYear = new Date().getFullYear()
const minYearsSupported = 8
const maxYearsSupported = 149

function zeroPad(x = '') {
  return x.length === 1 ? `0${x}` : x
}

const calculateDateOptions = () => ({
  dayOptions: listOfDays().map((day) => ({
    value: zeroPad(day),
    label: day,
  })),
  monthOptions: listOfMonths().map((month, index) => ({
    value: zeroPad(String(index + 1)),
    label: month,
  })),
  yearOptions: listOfYears(currentYear - minYearsSupported, currentYear - maxYearsSupported).map((year) => ({
    value: year,
    label: year,
  })),
})

export default function FormUserBirthDate({ disabled, id = '', dayName, monthName, yearName, onChangeYear }) {
  const { t, i18n } = useTranslation()
  const dayLabel = t('common-ui:day.label', 'Day')
  const monthLabel = t('common-ui:month.label', 'Month')
  const yearLabel = t('common-ui:year.label', 'Year')
  const { dayOptions, monthOptions, yearOptions } = useMemo(() => calculateDateOptions(i18n.language), [i18n.language]) // eslint-disable-line sonarjs/no-extra-arguments -- FIXME: re-enable this rule and fix the indicated infraction.
  const dayMonthYearOrder = useMemo(() => getDayMonthYearOrder(i18n.language), [i18n.language])
  const selectProps = {
    growX: true,
    disabled,
    validateAtGroupLevel: true,
  }
  const selects = {
    day: (
      <FormSelect
        id={`${id}birth-date-day`}
        data-testid="day-select"
        key={dayName}
        name={dayName}
        aria-label={dayLabel}
        placeholder={dayLabel}
        options={dayOptions}
        {...selectProps}
      />
    ),
    month: (
      <FormSelect
        id={`${id}birth-date-month`}
        data-testid="month-select"
        key={monthName}
        name={monthName}
        aria-label={monthLabel}
        placeholder={monthLabel}
        options={monthOptions}
        {...selectProps}
      />
    ),
    year: (
      <FormSelect
        id={`${id}birth-date-year`}
        data-testid="year-select"
        key={yearName}
        name={yearName}
        aria-label={yearLabel}
        placeholder={yearLabel}
        options={yearOptions}
        onChange={onChangeYear}
        {...selectProps}
      />
    ),
  }
  const orderedSelects = dayMonthYearOrder.map((x) => selects[x])
  return (
    <FormInputGroup
      // Keep year first here so that under-age validation messages can take precedence
      namesOfFieldsToValidate={[yearName, monthName, dayName]}
      label={t('birth-date.label', 'Birthdate')}
      disabled={disabled}
      id={`${id}birth-date-group`}
    >
      <Row wrap gutters="xxs">
        {orderedSelects}
      </Row>
    </FormInputGroup>
  )
}
