// Returns the ordering for day, month, and year for the provided locale
// (or default locale if no locale is provided).
// (e.g. ['day', 'month', 'year'])
// For more details see:
// https://github.com/fs-eng/qa-shared-i18n-checks/blob/master/dateCheck.js

const day = 'day'
const month = 'month'
const year = 'year'

const bigEndianLangs = ['hu', 'ja', 'ko', 'zh', 'zh-hans']

export default function getDayMonthYearOrder(langCode) {
  if (langCode === 'en') {
    return [month, day, year]
  }
  if (bigEndianLangs.includes(langCode)) {
    return [year, month, day]
  }
  return [day, month, year]
}
