/**
 * As of right now this determines years of age by treating the user's birthdate as happening at the beginning of the UTC day
 *
 * See other weird conversations such as https://familysearch.slack.com/archives/G0MQQ6A81/p1652302894182369
 * which discusses differences in how this is calculated in different UIs, node.js, and identity-cis.
 * After some experimentation it appears that identity-cis server's implementation relies on the server time
 * which seems to be set to UTC so it works. Current constraint is angular UI which requires day after your birthday.
 *
 * Current implementation here is the "it's your birthday per universal time".
 * Alternative would be "it's your birthday somewhere" (subtract 14 hours from UTC).
 */

import { differenceInYears } from '@fs/zion-locale/date-fns'

const ISO_BIRTH_DATE = /^[0-9]{4}-[0-9]{2}-[0-9]{2}$/

export default function getAgeUtc(birthDateAsIsoString, now = new Date()) {
  if (!ISO_BIRTH_DATE.test(birthDateAsIsoString)) {
    throw new Error('Please pass only only an ISO format for a date (e.g. "1999-05-14")')
  }
  // treat as UTC time at 12 am
  const isoBirthDate = new Date(birthDateAsIsoString)
  // Assume born on 12 am UTC which roughly splits the difference between possible timezones
  const birthDate = isoBirthDate
  return differenceInYears(now, birthDate)
}
