import axios from '@fs/zion-axios'
import { clearCachedSession, getSessionId } from '@fs/zion-session'
import { clearCachedUser } from '@fs/zion-user'

function refreshHelperMode(url) {
  clearCachedUser()
  clearCachedSession(getSessionId())
  if (typeof window !== 'undefined') {
    if (url) {
      window.location.href = url
    } else {
      window.location.reload()
    }
  }
}

async function stopHelping(url) {
  try {
    await axios.post('/ident/finishedHelping')
    refreshHelperMode(url)
  } catch (error) {
    console.error(error)
  }
}

async function startHelping(url, data, refreshUrl) {
  const response = await axios.post(url, data)
  if (response.status === 200) {
    refreshHelperMode(refreshUrl)
  }
  return response
}

/**
 * @param {object} data Object with the following properties:
 *  * userName
 *  * helperPin
 * @param {string} url String to use when refreshing helper mode on start
 */
async function startHelpingUsername(data, url) {
  return startHelping('/ident/processUsername', data, url)
}

/**
 * @param {object} data Object with the following properties:
 *  * givenName
 *  * familyName
 *  * day
 *  * month
 *  * year
 *  * helperPin
 * @param {string} url String to use when refreshing helper mode on start
 */
async function startHelpingFullname(data, url) {
  return startHelping('/ident/processFullname', data, url)
}

export { stopHelping, startHelpingUsername, startHelpingFullname }
