import React, { useCallback, useEffect, useState } from 'react'
import * as Yup from 'yup'
import { yupResolver } from '@hookform/resolvers/yup'
import {
  DialogOverlay,
  DialogOverlayActions,
  DialogOverlayFooter,
  Button,
  useStatusOverlay,
  Tabs,
  Tab,
  Paragraph,
  Alert,
  InlineButton,
} from '@fs/zion-ui'
import { Link } from '@fs/zion-router'
import { useTranslation, Trans } from 'react-i18next'
import ZionForm, { useZionForm, FormTextField } from '@fs/zion-form'
import { NoticeLoading } from '@fs/zion-icon'
import { exitRole } from '@fs/zion-admin-mode'
import { i18n } from '@fs/zion-locale'
import { useHelpOverlay } from '@fs/zion-help-overlay'
import { startHelpingUsername, startHelpingFullname } from './utils'
import FormUserBirthDate from './FormUserBirthDate'
import getDayMonthYearOrder from './getDayMonthYearOrder'
import getAge from './getAge'

const defaultValues = {
  userName: '',
  givenName: '',
  familyName: '',
  year: '',
  month: '',
  day: '',
  helperPin: '',
}
function zeroPad(x = '') {
  return x.length === 1 ? `0${x}` : x
}

export const userBirthDate = (age = 8, { yearName = 'year', monthName = 'month', dayName = 'day' } = {}) =>
  Yup.string()
    .trim()
    .required(i18n.t('birthdate_required', 'Birth date is required'))
    .test(
      'user-birth-date',
      () => i18n.t('account-age.validation', 'You must be at least {age} years old to create an account.'),
      (value, { parent: { [yearName]: year, [monthName]: month, [dayName]: day }, path }) => {
        if (!year || !month || !day) {
          return true
        }
        const [, , lastPath] = getDayMonthYearOrder(i18n.language)
        const dayMonthYearOrderMap = {
          year: yearName,
          month: monthName,
          day: dayName,
        }
        const pathToCheck = dayMonthYearOrderMap[lastPath]
        if (path !== pathToCheck) {
          // Only do the age check for the last field for the following reason:
          // 1) More efficient to do it once and do it on the field that likely has all data filled in.
          // 2) zion-form "validateAtGroupLevel" prop was not intended to clear the invalid state of the field unless the field value changes.
          //    Therefore, only the changed field will clear the error state when the issue is resolved (until submit or re-touch of the other fields)
          //    So we're only applying the error on one field and making a guess that it will often be the last field that is the issue
          //    which will often be the case when it's the year (most locales). If the guess is wrong then it's still more natural
          //    for a blur event to occur on the last field than the first or second.
          //    This isn't perfect but should have less issues than having the error stick around for every field.
          return true
        }
        return getAge(`${year}-${zeroPad(month)}-${zeroPad(day)}`) >= age
      }
    )
export default function HelperDialog({ overlay, redirectAfterStartUrl, adminActiveRole }) {
  const [loading, setLoading] = useState(false)
  const [selected, setSelected] = useState(0)
  const [hasFormError, setFormError] = useState(false) // invalid username or password
  const showStatusOverlay = useStatusOverlay()
  const { t } = useTranslation()
  const { close } = overlay
  const birthDateSchema = userBirthDate()
  const { handleClick } = useHelpOverlay('/help/helpcenter/article/what-does-a-helper-do')
  const validationSchema = Yup.object().shape(
    // preferredTab === 0
    selected === 0
      ? {
          userName: Yup.string()
            .required(t('username_required', 'Username is required'))
            .max(120, (params) =>
              t('username_maxlength', {
                maxLength: params.max,
                defaultValue: t('username.validation-error', 'Username can be at most {maxLength} characters'),
              })
            ),
          helperPin: Yup.string()
            .required(t('helperPin_required', 'Helper Number is required'))
            .max(20, (params) =>
              t('helperpin_maxlength', {
                maxLength: params.max,
                defaultValue: t('helper-pin.validation-error', 'Helper Pin can be at most {maxLength} characters'),
              })
            ),
        }
      : {
          givenName: Yup.string()
            .required(t('givenName_required', 'Given Name is required'))
            .max(20, (params) =>
              t('givenname_maxlength', {
                maxLength: params.max,
                defaultValue: t('given-name.validation-error', 'Given name can be at most {maxLength} characters'),
              })
            ),
          familyName: Yup.string()
            .required(t('surname_required', 'Family Name is required'))
            .max(20, (params) =>
              t('surname_maxlength', {
                maxLength: params.max,
                defaultValue: t('surname.validation-error', 'Surname can be at most {maxLength} characters'),
              })
            ),
          helperPin: Yup.string()
            .required(t('helperPin_required', 'Helper Number is required'))
            .max(20, (params) =>
              t('helperpin_maxlength', {
                maxLength: params.max,
                defaultValue: t('helper-pin.validation-error', 'Username can be at most {maxLength} characters'),
              })
            ),
          year: birthDateSchema,
          day: birthDateSchema,
          month: birthDateSchema,
        }
  )

  const submit = useCallback(
    async (values) => {
      setLoading(true)
      try {
        if (adminActiveRole) {
          await exitRole()
        }
        if (selected === 0) await startHelpingUsername(values, redirectAfterStartUrl)
        else await startHelpingFullname(values, redirectAfterStartUrl)
      } catch (error) {
        if (error?.response?.status === 400) {
          setFormError(true)
        } else {
          showStatusOverlay({
            message: t(
              'server_error',
              'Sorry. There was a problem starting helper mode. You may need to try again later.'
            ),
            type: 'error',
          })
          close()
        }
      }
      setLoading(false)
    },
    [adminActiveRole, selected, redirectAfterStartUrl, showStatusOverlay, t, close]
  )

  const methods = useZionForm({
    defaultValues,
    resolver: yupResolver(validationSchema),
    mode: 'all',
  })

  const {
    formState: { isValid },
    setError,
    clearErrors,
  } = methods

  useEffect(() => {
    if (hasFormError) {
      setError('helperPin', {
        type: 'custom',
        message: t('username_or_helper_number.error', 'The username or helper number is incorrect. Please try again.'),
      })
    }
  }, [hasFormError, setError, t])

  const resetHasFormError = useCallback(() => {
    clearErrors()
    setFormError(false)
  }, [clearErrors])

  return (
    <DialogOverlay
      title={t('help.others', 'Help Others')}
      {...overlay}
      as={ZionForm}
      methods={methods}
      onSubmit={submit}
    >
      <Tabs index={selected} fullWidth onChange={(ind) => setSelected(ind)}>
        <Tab title={t('helper-dialog.username-tab.title', 'Username')} data-testid="username-tab">
          <Paragraph>{t('whom.to.help', 'Whom do you want to help?')}</Paragraph>
          <FormTextField
            name="userName"
            label={t('common-ui:username.label', 'Username')}
            status={hasFormError ? 'error' : undefined}
            onChange={resetHasFormError}
            placeholder={t('user-name.placeholder', 'Enter his or her username')}
          />
          <FormTextField
            name="helperPin"
            label={t('helpernumber_label', 'Helper Number')}
            onChange={resetHasFormError}
            placeholder={t('helper-number.placeholder', 'Enter his or her helper number')}
            helpMessage={
              <Trans i18nKey="helper-dialog.help-message">
                You can find and change your helper number in the{' '}
                <Link to="/identity/settings/permissions" external target="_blank">
                  Permissions tab
                </Link>{' '}
                in your account settings.
              </Trans>
            }
          />
        </Tab>
        <Tab title={t('helper-dialog.full-name-tab.title', 'Full Name')} data-testid="fullname-tab">
          <Paragraph>{t('whom.to.help', 'Whom do you want to help?')}</Paragraph>
          <FormTextField
            name="givenName"
            label={t('given-name.label', 'Given Name')}
            status={hasFormError ? 'error' : undefined}
            onChange={resetHasFormError}
            placeholder={t('given-name.placeholder', 'Enter his or her given name')}
          />
          <FormTextField
            name="familyName"
            label={t('family-name.label', 'Family Name')}
            status={hasFormError ? 'error' : undefined}
            onChange={resetHasFormError}
            placeholder={t('family-name.placeholder', 'Enter his or her family name')}
          />
          <FormUserBirthDate yearName="year" monthName="month" dayName="day" />
          <FormTextField
            name="helperPin"
            label={t('helpernumber_label', 'Helper Number')}
            onChange={resetHasFormError}
            placeholder={t('helper-number.placeholder', 'Enter his or her helper number')}
            helpMessage={
              <Trans i18nKey="helper-dialog.help-message">
                You can find and change your helper number in the{' '}
                <Link to="/identity/settings/permissions" external target="_blank">
                  Permissions tab
                </Link>{' '}
                in your account settings.
              </Trans>
            }
          />
        </Tab>
      </Tabs>
      <Alert outlined>
        {t(
          'helper-alert.message',
          'When you give your helper number to others, they can access and edit your Family Tree information.'
        )}{' '}
        <InlineButton onClick={handleClick}>{t('helper-alert.message-link', 'Learn more')}</InlineButton>
      </Alert>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button emphasis="low" onClick={overlay.close}>
            {t('common-ui:cancel.action', 'Cancel')}
          </Button>
          <Button emphasis="high" disabled={!isValid} type="submit" Icon={loading ? NoticeLoading : undefined}>
            {t('common-ui:sign-in.action', 'Sign In')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
